class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def nextGreaterNodes(head):
    result = []
    stack = []
    while head:
        while stack and stack[-1] < head.val:
            stack[-1] = head.val
            stack.pop()
        result.append(head.val)
        stack.append(len(result) - 1)
        head = head.next

    while stack:
        result[stack.pop()] = 0

    return result
```

