public class ListNode {
    int val;
    ListNode next;
    ListNode(int x) { val = x; }
}

public int[] nextGreaterNodes(ListNode head) {
    Stack<Integer> greater = new Stack<>();
    ListNode current = head;
    int size = 0;

    while (current != null) {
        size++;
        current = current.next;
    }

    int[] answer = new int[size];
    int index = 0;

    current = head;

    while (current != null) {
        while (!greater.empty() && answer[greater.peek()] < current.val) {
            answer[greater.pop()] = current.val;
        }
        answer[index] = current.val;
        greater.push(index++);
        current = current.next;
    }

    while (!greater.empty()) {
        answer[greater.pop()] = 0;
    }
    return answer;
}
